"use client"

import * as React from "react"

import {
  disposeAutoScrollSession,
  prefersReducedMotion,
  startAutoScrollSession,
  type AutoScrollSession,
} from "../lib/df-dnd"
import {
  anchorsFromBars,
  buildTimelineScale,
  formatTimelineDateRange,
  layoutTimelineBars,
  nudgeTimelineBar,
  reduceTimelineDrag,
  routeDependencyPaths,
  type TimelineBarRect,
  type TimelineDependencyEdge,
  type TimelineDragKind,
  type TimelineVisibleRange,
  type TimelineZoom,
} from "../lib/df-timeline"
import { useVirtualRows } from "../lib/df-virtual"
import { cn } from "../lib/utils"

const LOADING_ROW_COUNT = 8
const DEFAULT_UNIT_PX = 40
const DEFAULT_ROW_HEIGHT = 36
const DEFAULT_LABEL_WIDTH = 220

export type TimelineRow = {
  id: string
  label: React.ReactNode
  start?: string
  due?: string
  progress?: number
  /** CSS custom property name used as the bar fill, e.g. `--success`. */
  colorToken?: string
}

export type TimelineBarChange = {
  start: string
  due: string
}

export type TimelineProps = Omit<
  React.HTMLAttributes<HTMLDivElement>,
  "children"
> & {
  rows: TimelineRow[]
  dependencies?: TimelineDependencyEdge[]
  zoom?: TimelineZoom
  visibleRange: TimelineVisibleRange
  loading?: boolean
  emptyContent?: React.ReactNode
  overscan?: number
  estimateRowSize?: number
  onBarChange?: (id: string, next: TimelineBarChange) => void
  onRowClick?: (id: string) => void
  renderRowMeta?: (row: TimelineRow) => React.ReactNode
}

type PointerDragSession = {
  pointerId: number
  kind: TimelineDragKind
  rowId: string
  originStart: string
  originDue: string
  originX: number
  originWidth: number
  startClientX: number
  scrollLeftAtStart: number
}

type DragPreview = {
  rowId: string
  kind: TimelineDragKind
  start: string
  due: string
  translateX: number
  widthScale: number
}

type KeyboardDraft = {
  rowId: string
  originStart: string
  originDue: string
  draftStart: string
  draftDue: string
}

function readCssPx(token: string, fallback: number): number {
  if (typeof document === "undefined") return fallback
  const raw = getComputedStyle(document.documentElement)
    .getPropertyValue(token)
    .trim()
  const px = Number.parseFloat(raw)
  return Number.isFinite(px) && px > 0 ? px : fallback
}

function resolveBarDates(row: TimelineRow): TimelineBarChange | null {
  if (!row.start && !row.due) return null
  if (row.start && row.due) return { start: row.start, due: row.due }
  if (row.start) return { start: row.start, due: row.start }
  return { start: row.due!, due: row.due! }
}

function rowAriaName(row: TimelineRow): string {
  return typeof row.label === "string" && row.label.trim()
    ? row.label
    : "Item"
}

function Timeline({
  className,
  rows,
  dependencies = [],
  zoom = "day",
  visibleRange,
  loading = false,
  emptyContent,
  overscan = 6,
  estimateRowSize: estimateRowSizeProp,
  onBarChange,
  onRowClick,
  renderRowMeta,
  style,
  "aria-label": ariaLabel = "Timeline",
  ...props
}: TimelineProps) {
  const labelScrollRef = React.useRef<HTMLDivElement>(null)
  const gridScrollRef = React.useRef<HTMLDivElement>(null)
  const headerScrollRef = React.useRef<HTMLDivElement>(null)
  const syncingScrollRef = React.useRef(false)
  const dragSessionRef = React.useRef<PointerDragSession | null>(null)
  const dragPreviewRef = React.useRef<DragPreview | null>(null)
  const dragCaptureTargetRef = React.useRef<HTMLElement | null>(null)
  const autoScrollSession = React.useRef<AutoScrollSession | null>(null)

  const [liveMessage, setLiveMessage] = React.useState("")
  const [activePointerDrag, setActivePointerDrag] = React.useState(false)
  const [dragPreview, setDragPreview] = React.useState<DragPreview | null>(null)
  const [keyboardDraft, setKeyboardDraft] = React.useState<KeyboardDraft | null>(
    null
  )

  const unitPx = readCssPx("--df-timeline-unit-px", DEFAULT_UNIT_PX)
  const rowHeight =
    estimateRowSizeProp ??
    readCssPx("--df-timeline-row-height", DEFAULT_ROW_HEIGHT)
  const labelWidth = readCssPx("--df-timeline-label-width", DEFAULT_LABEL_WIDTH)
  const stubPx = readCssPx("--df-timeline-dependency-stub", 8)
  const radiusPx = readCssPx("--df-timeline-dependency-radius", 4)

  const scale = React.useMemo(
    () =>
      buildTimelineScale({
        visibleRange,
        zoom,
        unitPx,
      }),
    [unitPx, visibleRange, zoom]
  )

  const effectiveRows = React.useMemo(() => {
    if (!keyboardDraft) return rows
    return rows.map((row) =>
      row.id === keyboardDraft.rowId
        ? {
            ...row,
            start: keyboardDraft.draftStart,
            due: keyboardDraft.draftDue,
          }
        : row
    )
  }, [keyboardDraft, rows])

  const barRects = React.useMemo(
    () =>
      layoutTimelineBars(
        effectiveRows.map((row) => ({
          id: row.id,
          start: row.start,
          due: row.due,
          progress: row.progress,
        })),
        scale
      ),
    [effectiveRows, scale]
  )

  const barById = React.useMemo(() => {
    const map = new Map<string, TimelineBarRect>()
    for (const rect of barRects) map.set(rect.id, rect)
    return map
  }, [barRects])

  const rowIndexById = React.useMemo(() => {
    const map = new Map<string, number>()
    effectiveRows.forEach((row, index) => map.set(row.id, index))
    return map
  }, [effectiveRows])

  const dependencyPaths = React.useMemo(() => {
    const anchors = anchorsFromBars(barRects, rowIndexById)
    return routeDependencyPaths(dependencies, anchors, {
      rowHeight,
      stubPx,
      radiusPx,
    })
  }, [barRects, dependencies, radiusPx, rowHeight, rowIndexById, stubPx])

  const { items, totalSize, measureElement } = useVirtualRows({
    count: loading || rows.length === 0 ? 0 : rows.length,
    estimateSize: rowHeight,
    getScrollElement: () => gridScrollRef.current,
    overscan,
  })

  const announce = React.useCallback((message: string) => {
    setLiveMessage(message)
  }, [])

  const syncLabelScroll = React.useCallback(() => {
    const grid = gridScrollRef.current
    const labels = labelScrollRef.current
    if (!grid || !labels || syncingScrollRef.current) return
    if (labels.scrollTop !== grid.scrollTop) {
      syncingScrollRef.current = true
      labels.scrollTop = grid.scrollTop
      syncingScrollRef.current = false
    }
  }, [])

  const syncHeaderScroll = React.useCallback(() => {
    const grid = gridScrollRef.current
    const header = headerScrollRef.current
    if (!grid || !header) return
    if (header.scrollLeft !== grid.scrollLeft) {
      header.scrollLeft = grid.scrollLeft
    }
  }, [])

  const onGridScroll = React.useCallback(() => {
    syncLabelScroll()
    syncHeaderScroll()
  }, [syncHeaderScroll, syncLabelScroll])

  const onLabelScroll = React.useCallback(() => {
    const grid = gridScrollRef.current
    const labels = labelScrollRef.current
    if (!grid || !labels || syncingScrollRef.current) return
    if (grid.scrollTop !== labels.scrollTop) {
      syncingScrollRef.current = true
      grid.scrollTop = labels.scrollTop
      syncingScrollRef.current = false
    }
  }, [])

  React.useEffect(() => {
    const header = headerScrollRef.current
    if (!header) return
    const onWheel = (event: WheelEvent) => {
      const grid = gridScrollRef.current
      if (!grid) return
      const deltaX =
        event.deltaX !== 0 ? event.deltaX : event.shiftKey ? event.deltaY : 0
      const deltaY =
        event.deltaX !== 0 || event.shiftKey ? 0 : event.deltaY
      if (deltaX === 0 && deltaY === 0) return
      event.preventDefault()
      if (deltaX !== 0) grid.scrollLeft += deltaX
      if (deltaY !== 0) grid.scrollTop += deltaY
    }
    header.addEventListener("wheel", onWheel, { passive: false })
    return () => header.removeEventListener("wheel", onWheel)
  }, [])

  const stopAutoScroll = React.useCallback(() => {
    disposeAutoScrollSession(autoScrollSession)
  }, [])

  const updateDragPreview = React.useCallback((next: DragPreview | null) => {
    dragPreviewRef.current = next
    setDragPreview(next)
  }, [])

  const endPointerDrag = React.useCallback(() => {
    const session = dragSessionRef.current
    if (!session) return null
    const preview = dragPreviewRef.current
    const target = dragCaptureTargetRef.current
    if (target?.hasPointerCapture?.(session.pointerId)) {
      target.releasePointerCapture(session.pointerId)
    }
    dragCaptureTargetRef.current = null
    dragSessionRef.current = null
    updateDragPreview(null)
    setActivePointerDrag(false)
    stopAutoScroll()
    return { session, preview }
  }, [stopAutoScroll, updateDragPreview])

  const commitBarChange = React.useCallback(
    (rowId: string, next: TimelineBarChange, origin: TimelineBarChange) => {
      if (next.start === origin.start && next.due === origin.due) {
        announce("Bar unchanged")
        return
      }
      onBarChange?.(rowId, next)
      announce(`Updated ${formatTimelineDateRange(next.start, next.due)}`)
    },
    [announce, onBarChange]
  )

  const applyPointerDelta = React.useCallback(
    (session: PointerDragSession, clientX: number) => {
      const grid = gridScrollRef.current
      const scrollDelta = grid
        ? grid.scrollLeft - session.scrollLeftAtStart
        : 0
      const deltaPx = clientX - session.startClientX + scrollDelta
      const proposed = reduceTimelineDrag({
        kind: session.kind,
        origin: { start: session.originStart, due: session.originDue },
        deltaPx,
        scale,
      })

      let translateX = 0
      let widthScale = 1
      if (session.kind === "move") {
        translateX = scale.dateToX(proposed.start) - session.originX
      } else if (session.kind === "resize-end") {
        const nextWidth = Math.max(
          scale.unitPx,
          scale.dateToX(proposed.due) + scale.unitPx - session.originX
        )
        widthScale = nextWidth / Math.max(session.originWidth, 1)
      } else {
        const nextX = scale.dateToX(proposed.start)
        const nextWidth = Math.max(
          scale.unitPx,
          session.originX + session.originWidth - nextX
        )
        translateX = nextX - session.originX
        widthScale = nextWidth / Math.max(session.originWidth, 1)
      }

      updateDragPreview({
        rowId: session.rowId,
        kind: session.kind,
        start: proposed.start,
        due: proposed.due,
        translateX,
        widthScale,
      })
    },
    [scale, updateDragPreview]
  )

  React.useEffect(() => {
    if (!activePointerDrag) return
    const session = dragSessionRef.current
    if (!session) return

    const onMove = (event: PointerEvent) => {
      if (event.pointerId !== session.pointerId) return
      autoScrollSession.current?.updatePointer(event.clientX, event.clientY)
      applyPointerDelta(session, event.clientX)
    }

    const finish = (event: PointerEvent, cancelled: boolean) => {
      if (event.pointerId !== session.pointerId) return
      const ended = endPointerDrag()
      if (!ended) return
      if (
        cancelled ||
        !ended.preview ||
        ended.preview.rowId !== ended.session.rowId
      ) {
        announce("Bar drag cancelled")
        return
      }
      commitBarChange(
        ended.session.rowId,
        { start: ended.preview.start, due: ended.preview.due },
        {
          start: ended.session.originStart,
          due: ended.session.originDue,
        }
      )
    }

    const onUp = (event: PointerEvent) => finish(event, false)
    const onCancel = (event: PointerEvent) => finish(event, true)
    const onKeyDown = (event: KeyboardEvent) => {
      if (event.key !== "Escape") return
      event.preventDefault()
      const ended = endPointerDrag()
      if (!ended) return
      announce("Bar drag cancelled")
    }

    window.addEventListener("pointermove", onMove)
    window.addEventListener("pointerup", onUp)
    window.addEventListener("pointercancel", onCancel)
    window.addEventListener("keydown", onKeyDown)
    return () => {
      window.removeEventListener("pointermove", onMove)
      window.removeEventListener("pointerup", onUp)
      window.removeEventListener("pointercancel", onCancel)
      window.removeEventListener("keydown", onKeyDown)
      stopAutoScroll()
    }
  }, [
    activePointerDrag,
    announce,
    applyPointerDelta,
    commitBarChange,
    endPointerDrag,
    stopAutoScroll,
  ])

  const beginPointerDrag = React.useCallback(
    (
      event: React.PointerEvent<HTMLElement>,
      row: TimelineRow,
      kind: TimelineDragKind,
      rect: TimelineBarRect
    ) => {
      if (event.button !== 0 || (!row.start && !row.due)) return
      const dates = resolveBarDates(row)
      if (!dates) return
      event.preventDefault()
      event.stopPropagation()

      const originStart = scale.snapDate(dates.start)
      const originDue = scale.snapDate(dates.due)
      dragSessionRef.current = {
        pointerId: event.pointerId,
        kind,
        rowId: row.id,
        originStart,
        originDue,
        originX: rect.x,
        originWidth: rect.width,
        startClientX: event.clientX,
        scrollLeftAtStart: gridScrollRef.current?.scrollLeft ?? 0,
      }
      setKeyboardDraft(null)
      updateDragPreview({
        rowId: row.id,
        kind,
        start: originStart,
        due: originDue,
        translateX: 0,
        widthScale: 1,
      })
      setActivePointerDrag(true)
      announce(
        kind === "move"
          ? `Moving bar ${formatTimelineDateRange(originStart, originDue)}`
          : `Resizing bar ${formatTimelineDateRange(originStart, originDue)}`
      )
      stopAutoScroll()
      autoScrollSession.current = startAutoScrollSession({
        axis: "both",
        getContainer: () => gridScrollRef.current,
      })
      dragCaptureTargetRef.current = event.currentTarget
      event.currentTarget.setPointerCapture?.(event.pointerId)
    },
    [announce, scale, stopAutoScroll, updateDragPreview]
  )

  const onBarKeyDown = React.useCallback(
    (event: React.KeyboardEvent<HTMLElement>, row: TimelineRow) => {
      const liveRow =
        keyboardDraft?.rowId === row.id
          ? {
              ...row,
              start: keyboardDraft.draftStart,
              due: keyboardDraft.draftDue,
            }
          : row
      const dates = resolveBarDates(liveRow)
      if (!dates) return

      if (event.key === "Escape") {
        if (!keyboardDraft || keyboardDraft.rowId !== row.id) return
        event.preventDefault()
        setKeyboardDraft(null)
        announce("Bar edit cancelled")
        return
      }

      if (event.key === "Enter") {
        if (!keyboardDraft || keyboardDraft.rowId !== row.id) return
        event.preventDefault()
        const next = {
          start: keyboardDraft.draftStart,
          due: keyboardDraft.draftDue,
        }
        const origin = {
          start: keyboardDraft.originStart,
          due: keyboardDraft.originDue,
        }
        setKeyboardDraft(null)
        commitBarChange(row.id, next, origin)
        return
      }

      if (event.key !== "ArrowLeft" && event.key !== "ArrowRight") return
      event.preventDefault()
      const units = event.key === "ArrowRight" ? 1 : -1
      const kind: TimelineDragKind = event.altKey
        ? "resize-start"
        : event.shiftKey
          ? "resize-end"
          : "move"
      const origin =
        keyboardDraft?.rowId === row.id
          ? {
              start: keyboardDraft.originStart,
              due: keyboardDraft.originDue,
            }
          : dates
      const next = nudgeTimelineBar({
        kind,
        origin: dates,
        units,
        scale,
      })
      setKeyboardDraft({
        rowId: row.id,
        originStart: origin.start,
        originDue: origin.due,
        draftStart: next.start,
        draftDue: next.due,
      })
      announce(
        `${kind === "move" ? "Moved" : "Resized"} to ${formatTimelineDateRange(next.start, next.due)}. Press Enter to commit.`
      )
    },
    [announce, commitBarChange, keyboardDraft, scale]
  )

  const isEmpty = !loading && rows.length === 0
  const reducedMotion = prefersReducedMotion()
  const weekendColumns =
    zoom === "day"
      ? scale.fineColumns.filter((column) => column.isWeekend)
      : []

  return (
    <div
      {...props}
      data-df="timeline"
      data-zoom={zoom}
      data-loading={loading ? "true" : undefined}
      data-empty={isEmpty ? "true" : undefined}
      className={cn("df-timeline", className)}
      style={style}
      role="treegrid"
      aria-label={ariaLabel}
      aria-rowcount={loading ? LOADING_ROW_COUNT + 1 : rows.length + 1}
      aria-busy={loading || undefined}
    >
      <div className="df-timeline-chrome" data-df="timeline-chrome">
        <div
          className="df-timeline-corner"
          data-df="timeline-corner"
          style={{ width: labelWidth, minWidth: labelWidth }}
        >
          <span className="df-timeline-corner-label">Name</span>
        </div>
        <div
          ref={headerScrollRef}
          className="df-timeline-header-scroll"
          data-df="timeline-header-scroll"
        >
          <div
            className="df-timeline-header"
            data-df="timeline-header"
            style={{ width: scale.totalWidth }}
          >
            <div
              className="df-timeline-header-row"
              data-df="timeline-header-coarse"
            >
              {scale.coarseHeaders.map((cell) => (
                <div
                  key={cell.key}
                  className="df-timeline-header-cell"
                  style={{ left: cell.x, width: cell.width }}
                >
                  {cell.label}
                </div>
              ))}
            </div>
            <div
              className="df-timeline-header-row"
              data-df="timeline-header-fine"
            >
              {scale.fineHeaders.map((cell) => (
                <div
                  key={cell.key}
                  className="df-timeline-header-cell"
                  style={{ left: cell.x, width: cell.width }}
                >
                  {cell.label}
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>

      <div className="df-timeline-body" data-df="timeline-body">
        <div
          ref={labelScrollRef}
          className="df-timeline-labels"
          data-df="timeline-labels"
          style={{ width: labelWidth, minWidth: labelWidth }}
          onScroll={onLabelScroll}
        >
          {loading ? (
            <div className="df-timeline-loading" data-df="timeline-loading">
              {Array.from({ length: LOADING_ROW_COUNT }, (_, index) => (
                <div
                  key={`label-loading-${index}`}
                  className="df-timeline-label-row"
                  style={{ height: rowHeight }}
                >
                  <span className="df-timeline-skeleton" />
                </div>
              ))}
            </div>
          ) : isEmpty ? null : (
            <div className="df-timeline-label-rows" style={{ height: totalSize }}>
              {items.map((item) => {
                const row = effectiveRows[item.index]
                if (!row) return null
                return (
                  <div
                    key={row.id}
                    ref={measureElement}
                    data-index={item.index}
                    className="df-timeline-label-row"
                    data-df="timeline-label-row"
                    role="row"
                    aria-rowindex={item.index + 2}
                    style={{
                      position: "absolute",
                      top: 0,
                      left: 0,
                      width: "100%",
                      height: item.size,
                      transform: `translateY(${item.start}px)`,
                    }}
                    onClick={() => onRowClick?.(row.id)}
                  >
                    <div className="df-timeline-label-main">
                      <span className="df-timeline-label-text">{row.label}</span>
                      {renderRowMeta ? (
                        <span className="df-timeline-label-meta">
                          {renderRowMeta(row)}
                        </span>
                      ) : null}
                    </div>
                  </div>
                )
              })}
            </div>
          )}
        </div>

        <div
          ref={gridScrollRef}
          className="df-timeline-grid"
          data-df="timeline-grid"
          onScroll={onGridScroll}
        >
          {loading ? (
            <div
              className="df-timeline-loading"
              data-df="timeline-loading"
              style={{ width: scale.totalWidth }}
            >
              {Array.from({ length: LOADING_ROW_COUNT }, (_, index) => (
                <div
                  key={`grid-loading-${index}`}
                  className="df-timeline-track-row"
                  style={{ height: rowHeight, width: scale.totalWidth }}
                >
                  <span className="df-timeline-skeleton df-timeline-skeleton-bar" />
                </div>
              ))}
            </div>
          ) : isEmpty ? (
            <div
              className="df-timeline-empty"
              data-df="timeline-empty"
              role="status"
            >
              {emptyContent ?? "No rows"}
            </div>
          ) : (
            <div
              className="df-timeline-tracks"
              data-df="timeline-tracks"
              style={{ height: totalSize, width: scale.totalWidth }}
            >
              {weekendColumns.map((column) => (
                <div
                  key={`weekend-${column.key}`}
                  className="df-timeline-weekend"
                  data-df="timeline-weekend"
                  style={{ left: column.x, width: column.width }}
                />
              ))}

              {scale.fineColumns.map((column) => (
                <div
                  key={`col-${column.key}`}
                  className="df-timeline-column-line"
                  style={{ left: column.x }}
                />
              ))}

              {scale.todayX !== null ? (
                <div
                  className="df-timeline-today"
                  data-df="timeline-today"
                  style={{ left: scale.todayX }}
                />
              ) : null}

              <svg
                className="df-timeline-dependencies"
                data-df="timeline-dependencies"
                width={scale.totalWidth}
                height={totalSize}
                aria-hidden
              >
                {dependencyPaths.map((path) => (
                  <path
                    key={`${path.fromId}-${path.toId}`}
                    d={path.d}
                    className="df-timeline-dependency-path"
                  />
                ))}
              </svg>

              {items.map((item) => {
                const row = effectiveRows[item.index]
                if (!row) return null
                const rect = barById.get(row.id)
                const preview =
                  dragPreview?.rowId === row.id ? dragPreview : null
                const color = row.colorToken
                  ? `var(${row.colorToken})`
                  : undefined
                const labelDates = preview
                  ? formatTimelineDateRange(preview.start, preview.due)
                  : formatTimelineDateRange(
                      row.start ?? row.due ?? "",
                      row.due ?? row.start ?? ""
                    )

                return (
                  <div
                    key={row.id}
                    className="df-timeline-track-row"
                    data-df="timeline-track-row"
                    role="row"
                    aria-rowindex={item.index + 2}
                    style={{
                      position: "absolute",
                      top: 0,
                      left: 0,
                      width: scale.totalWidth,
                      height: item.size,
                      transform: `translateY(${item.start}px)`,
                    }}
                  >
                    {rect ? (
                      <div
                        className="df-timeline-bar"
                        data-df="timeline-bar"
                        data-missing-start={
                          rect.missingStart ? "true" : undefined
                        }
                        data-missing-due={rect.missingDue ? "true" : undefined}
                        data-dragging={preview ? "true" : undefined}
                        role="gridcell"
                        tabIndex={0}
                        aria-label={`${rowAriaName(row)} ${labelDates}`}
                        style={{
                          left: rect.x,
                          width: rect.width,
                          background: color,
                          transform: preview
                            ? `translateX(${preview.translateX}px) scaleX(${preview.widthScale})`
                            : undefined,
                          transformOrigin: "left center",
                          transition:
                            preview || reducedMotion
                              ? "none"
                              : "transform var(--df-duration-quick) var(--df-ease-standard)",
                        }}
                        onKeyDown={(event) => onBarKeyDown(event, row)}
                        onPointerDown={(event) =>
                          beginPointerDrag(event, row, "move", rect)
                        }
                      >
                        {rect.progress !== null ? (
                          <span
                            className="df-timeline-bar-progress"
                            style={{
                              width: `${Math.round(rect.progress * 100)}%`,
                            }}
                          />
                        ) : null}
                        <span
                          className="df-timeline-bar-handle df-timeline-bar-handle-start"
                          data-df="timeline-bar-handle"
                          data-edge="start"
                          onPointerDown={(event) =>
                            beginPointerDrag(event, row, "resize-start", rect)
                          }
                        />
                        <span
                          className="df-timeline-bar-handle df-timeline-bar-handle-end"
                          data-df="timeline-bar-handle"
                          data-edge="end"
                          onPointerDown={(event) =>
                            beginPointerDrag(event, row, "resize-end", rect)
                          }
                        />
                      </div>
                    ) : null}

                    {preview ? (
                      <div
                        className="df-timeline-ghost"
                        data-df="timeline-ghost"
                        style={{
                          left: scale.dateToX(preview.start),
                          width: Math.max(
                            scale.unitPx,
                            scale.dateToX(preview.due) +
                              scale.unitPx -
                              scale.dateToX(preview.start)
                          ),
                        }}
                      >
                        <span className="df-timeline-ghost-label">
                          {formatTimelineDateRange(preview.start, preview.due)}
                        </span>
                      </div>
                    ) : null}
                  </div>
                )
              })}
            </div>
          )}
        </div>
      </div>

      <div
        className="df-timeline-live"
        data-df="timeline-live"
        aria-live="polite"
        aria-atomic="true"
      >
        {liveMessage}
      </div>
    </div>
  )
}

export { Timeline }
export type { TimelineDependencyEdge, TimelineVisibleRange, TimelineZoom }

import {
  addUtcDays,
  formatUtcDate,
  startOfUtcDay,
  toDate,
} from "../df-date/index"

const MS_PER_DAY = 86_400_000

export type TimelineZoom = "day" | "week" | "month" | "quarter"

export type TimelineVisibleRange = {
  start: string
  end: string
}

export type TimelineHeaderCell = {
  key: string
  label: string
  start: string
  end: string
  x: number
  width: number
}

export type TimelineFineColumn = TimelineHeaderCell & {
  isWeekend: boolean
}

export type TimelineScale = {
  zoom: TimelineZoom
  rangeStart: string
  rangeEnd: string
  unitPx: number
  totalWidth: number
  fineColumns: TimelineFineColumn[]
  coarseHeaders: TimelineHeaderCell[]
  fineHeaders: TimelineHeaderCell[]
  todayX: number | null
  dateToX: (iso: string) => number
  xToDate: (px: number) => string
  snapDate: (iso: string) => string
  shiftDate: (iso: string, units: number) => string
  unitLabel: string
}

export type BuildTimelineScaleOptions = {
  visibleRange: TimelineVisibleRange
  zoom: TimelineZoom
  /** Pixels per fine tick unit. Typically read from `--df-timeline-unit-px`. */
  unitPx: number
  /** ISO date used for the today marker. Defaults to the current UTC day. */
  today?: string
}

type Span = {
  start: Date
  end: Date
  label: string
  key: string
  isWeekend: boolean
}

function assertPositiveUnitPx(unitPx: number): number {
  if (!Number.isFinite(unitPx) || unitPx <= 0) {
    throw new Error("unitPx must be a positive finite number")
  }
  return unitPx
}

function startOfUtcWeek(value: Date | string | number): Date {
  const day = startOfUtcDay(value)
  return addUtcDays(day, -day.getUTCDay())
}

function startOfUtcMonth(value: Date | string | number): Date {
  const day = startOfUtcDay(value)
  return new Date(Date.UTC(day.getUTCFullYear(), day.getUTCMonth(), 1))
}

function addUtcMonths(value: Date | string | number, months: number): Date {
  const day = startOfUtcDay(value)
  return new Date(
    Date.UTC(day.getUTCFullYear(), day.getUTCMonth() + months, 1)
  )
}

function startOfUtcQuarter(value: Date | string | number): Date {
  const day = startOfUtcDay(value)
  const quarterMonth = Math.floor(day.getUTCMonth() / 3) * 3
  return new Date(Date.UTC(day.getUTCFullYear(), quarterMonth, 1))
}

function monthLabel(date: Date): string {
  return date.toLocaleString("en-US", { month: "short", timeZone: "UTC" })
}

function yearLabel(date: Date): string {
  return String(date.getUTCFullYear())
}

function quarterLabel(date: Date): string {
  const q = Math.floor(date.getUTCMonth() / 3) + 1
  return `Q${q} ${date.getUTCFullYear()}`
}

function dayLabel(date: Date): string {
  return String(date.getUTCDate())
}

function weekLabel(date: Date): string {
  const end = addUtcDays(date, 6)
  return `${monthLabel(date)} ${dayLabel(date)}-${dayLabel(end)}`
}

function enumerateFineSpans(
  zoom: TimelineZoom,
  rangeStart: Date,
  rangeEndExclusive: Date
): Span[] {
  const spans: Span[] = []
  if (zoom === "day") {
    let cursor = rangeStart
    while (cursor.getTime() < rangeEndExclusive.getTime()) {
      const next = addUtcDays(cursor, 1)
      const weekday = cursor.getUTCDay()
      spans.push({
        start: cursor,
        end: next,
        label: dayLabel(cursor),
        key: formatUtcDate(cursor),
        isWeekend: weekday === 0 || weekday === 6,
      })
      cursor = next
    }
    return spans
  }

  if (zoom === "week") {
    let cursor = startOfUtcWeek(rangeStart)
    while (cursor.getTime() < rangeEndExclusive.getTime()) {
      const next = addUtcDays(cursor, 7)
      const visibleStart =
        cursor.getTime() < rangeStart.getTime() ? rangeStart : cursor
      if (visibleStart.getTime() < rangeEndExclusive.getTime()) {
        const visibleEnd =
          next.getTime() > rangeEndExclusive.getTime()
            ? rangeEndExclusive
            : next
        spans.push({
          start: visibleStart,
          end: visibleEnd,
          label: weekLabel(cursor),
          key: formatUtcDate(cursor),
          isWeekend: false,
        })
      }
      cursor = next
    }
    return spans
  }

  if (zoom === "month") {
    let cursor = startOfUtcMonth(rangeStart)
    while (cursor.getTime() < rangeEndExclusive.getTime()) {
      const next = addUtcMonths(cursor, 1)
      const visibleStart =
        cursor.getTime() < rangeStart.getTime() ? rangeStart : cursor
      if (visibleStart.getTime() < rangeEndExclusive.getTime()) {
        const visibleEnd =
          next.getTime() > rangeEndExclusive.getTime()
            ? rangeEndExclusive
            : next
        spans.push({
          start: visibleStart,
          end: visibleEnd,
          label: `${monthLabel(cursor)} ${yearLabel(cursor)}`,
          key: `${cursor.getUTCFullYear()}-${String(cursor.getUTCMonth() + 1).padStart(2, "0")}`,
          isWeekend: false,
        })
      }
      cursor = next
    }
    return spans
  }

  let cursor = startOfUtcQuarter(rangeStart)
  while (cursor.getTime() < rangeEndExclusive.getTime()) {
    const next = addUtcMonths(cursor, 3)
    const visibleStart =
      cursor.getTime() < rangeStart.getTime() ? rangeStart : cursor
    if (visibleStart.getTime() < rangeEndExclusive.getTime()) {
      const visibleEnd =
        next.getTime() > rangeEndExclusive.getTime()
          ? rangeEndExclusive
          : next
      spans.push({
        start: visibleStart,
        end: visibleEnd,
        label: quarterLabel(cursor),
        key: `${cursor.getUTCFullYear()}-Q${Math.floor(cursor.getUTCMonth() / 3) + 1}`,
        isWeekend: false,
      })
    }
    cursor = next
  }
  return spans
}

function enumerateCoarseSpans(
  zoom: TimelineZoom,
  fine: Span[]
): Array<{ start: Date; end: Date; label: string; key: string }> {
  if (fine.length === 0) return []

  if (zoom === "day" || zoom === "week") {
    const groups: Array<{ start: Date; end: Date; label: string; key: string }> =
      []
    for (const span of fine) {
      const monthStart = startOfUtcMonth(span.start)
      const key = `${monthStart.getUTCFullYear()}-${String(monthStart.getUTCMonth() + 1).padStart(2, "0")}`
      const label = `${monthLabel(monthStart)} ${yearLabel(monthStart)}`
      const last = groups[groups.length - 1]
      if (last && last.key === key) {
        last.end = span.end
      } else {
        groups.push({ start: span.start, end: span.end, label, key })
      }
    }
    return groups
  }

  if (zoom === "month") {
    const groups: Array<{ start: Date; end: Date; label: string; key: string }> =
      []
    for (const span of fine) {
      const key = yearLabel(span.start)
      const last = groups[groups.length - 1]
      if (last && last.key === key) {
        last.end = span.end
      } else {
        groups.push({
          start: span.start,
          end: span.end,
          label: key,
          key,
        })
      }
    }
    return groups
  }

  const groups: Array<{ start: Date; end: Date; label: string; key: string }> =
    []
  for (const span of fine) {
    const key = yearLabel(span.start)
    const last = groups[groups.length - 1]
    if (last && last.key === key) {
      last.end = span.end
    } else {
      groups.push({
        start: span.start,
        end: span.end,
        label: key,
        key,
      })
    }
  }
  return groups
}

function snapDateToZoom(iso: string, zoom: TimelineZoom): string {
  const day = startOfUtcDay(iso)
  if (zoom === "day") return formatUtcDate(day)
  if (zoom === "week") return formatUtcDate(startOfUtcWeek(day))
  if (zoom === "month") return formatUtcDate(startOfUtcMonth(day))
  return formatUtcDate(startOfUtcQuarter(day))
}

function shiftDateByZoom(
  iso: string,
  zoom: TimelineZoom,
  units: number
): string {
  const day = startOfUtcDay(iso)
  if (zoom === "day") return formatUtcDate(addUtcDays(day, units))
  if (zoom === "week") return formatUtcDate(addUtcDays(startOfUtcWeek(day), units * 7))
  if (zoom === "month") {
    return formatUtcDate(addUtcMonths(startOfUtcMonth(day), units))
  }
  return formatUtcDate(addUtcMonths(startOfUtcQuarter(day), units * 3))
}

function unitLabelForZoom(zoom: TimelineZoom): string {
  if (zoom === "day") return "day"
  if (zoom === "week") return "week"
  if (zoom === "month") return "month"
  return "quarter"
}

/**
 * Build a linear time scale for the visible range and zoom preset.
 * Fine columns share a fixed pixel width (`unitPx`); date mapping interpolates inside each column.
 */
export function buildTimelineScale(
  options: BuildTimelineScaleOptions
): TimelineScale {
  const unitPx = assertPositiveUnitPx(options.unitPx)
  const zoom = options.zoom
  const rangeStart = startOfUtcDay(options.visibleRange.start)
  const rangeEndInclusive = startOfUtcDay(options.visibleRange.end)
  if (rangeEndInclusive.getTime() < rangeStart.getTime()) {
    throw new Error("visibleRange.end must be on or after visibleRange.start")
  }
  const rangeEndExclusive = addUtcDays(rangeEndInclusive, 1)

  const fineSpans = enumerateFineSpans(zoom, rangeStart, rangeEndExclusive)
  const fineColumns: TimelineFineColumn[] = fineSpans.map((span, index) => ({
    key: span.key,
    label: span.label,
    start: formatUtcDate(span.start),
    end: formatUtcDate(addUtcDays(span.end, -1)),
    x: index * unitPx,
    width: unitPx,
    isWeekend: span.isWeekend,
  }))

  const coarseSpans = enumerateCoarseSpans(zoom, fineSpans)
  let coarseX = 0
  const coarseHeaders: TimelineHeaderCell[] = coarseSpans.map((span) => {
    const startMs = span.start.getTime()
    const endMs = span.end.getTime()
    const columns = fineSpans.filter(
      (fine) =>
        fine.start.getTime() >= startMs && fine.start.getTime() < endMs
    )
    const width = columns.length * unitPx
    const cell: TimelineHeaderCell = {
      key: span.key,
      label: span.label,
      start: formatUtcDate(span.start),
      end: formatUtcDate(addUtcDays(span.end, -1)),
      x: coarseX,
      width,
    }
    coarseX += width
    return cell
  })

  const fineHeaders: TimelineHeaderCell[] = fineColumns.map((column) => ({
    key: column.key,
    label: column.label,
    start: column.start,
    end: column.end,
    x: column.x,
    width: column.width,
  }))

  const totalWidth = fineColumns.length * unitPx

  const dateToX = (iso: string): number => {
    const date = toDate(iso)
    if (fineSpans.length === 0) return 0
    if (date.getTime() <= fineSpans[0]!.start.getTime()) return 0
    const last = fineSpans[fineSpans.length - 1]!
    if (date.getTime() >= last.end.getTime()) return totalWidth

    for (let i = 0; i < fineSpans.length; i += 1) {
      const span = fineSpans[i]!
      if (date.getTime() >= span.end.getTime()) continue
      const spanMs = Math.max(MS_PER_DAY, span.end.getTime() - span.start.getTime())
      const t = (date.getTime() - span.start.getTime()) / spanMs
      return i * unitPx + t * unitPx
    }
    return totalWidth
  }

  const xToDate = (px: number): string => {
    if (fineSpans.length === 0) return formatUtcDate(rangeStart)
    const clamped = Math.min(Math.max(px, 0), Math.max(totalWidth - Number.EPSILON, 0))
    const index = Math.min(
      fineSpans.length - 1,
      Math.max(0, Math.floor(clamped / unitPx))
    )
    const span = fineSpans[index]!
    const local = clamped - index * unitPx
    const spanMs = Math.max(MS_PER_DAY, span.end.getTime() - span.start.getTime())
    const ms = span.start.getTime() + (local / unitPx) * spanMs
    return formatUtcDate(startOfUtcDay(ms))
  }

  const todayIso = formatUtcDate(
    startOfUtcDay(options.today ?? new Date().toISOString())
  )
  const todayMs = startOfUtcDay(todayIso).getTime()
  const todayInRange =
    todayMs >= rangeStart.getTime() && todayMs < rangeEndExclusive.getTime()
  const todayX = todayInRange ? dateToX(todayIso) : null

  return {
    zoom,
    rangeStart: formatUtcDate(rangeStart),
    rangeEnd: formatUtcDate(rangeEndInclusive),
    unitPx,
    totalWidth,
    fineColumns,
    coarseHeaders,
    fineHeaders,
    todayX,
    dateToX,
    xToDate,
    snapDate: (iso) => snapDateToZoom(iso, zoom),
    shiftDate: (iso, units) => shiftDateByZoom(iso, zoom, units),
    unitLabel: unitLabelForZoom(zoom),
  }
}

import type { TimelineScale } from "./scale"

export type TimelineBarInput = {
  id: string
  start?: string
  due?: string
  progress?: number
}

export type TimelineBarRect = {
  id: string
  x: number
  width: number
  missingStart: boolean
  missingDue: boolean
  progress: number | null
}

export type LayoutTimelineBarsOptions = {
  /** Width used when one date is missing. Defaults to one fine unit. */
  openEndedWidth?: number
  /** Minimum rendered bar width in pixels. */
  minWidth?: number
}

function clampProgress(value: number | undefined): number | null {
  if (value === undefined || !Number.isFinite(value)) return null
  return Math.min(1, Math.max(0, value))
}

/**
 * Project row dates onto the scale as bar rectangles.
 * Rows missing both dates produce no bar. A single missing bound yields an open-ended bar.
 */
export function layoutTimelineBars(
  rows: readonly TimelineBarInput[],
  scale: Pick<TimelineScale, "dateToX" | "unitPx" | "totalWidth">,
  options: LayoutTimelineBarsOptions = {}
): TimelineBarRect[] {
  const openEndedWidth = options.openEndedWidth ?? scale.unitPx
  const minWidth = options.minWidth ?? 1
  const rects: TimelineBarRect[] = []

  for (const row of rows) {
    const hasStart = typeof row.start === "string" && row.start.length > 0
    const hasDue = typeof row.due === "string" && row.due.length > 0
    if (!hasStart && !hasDue) continue

    const missingStart = !hasStart
    const missingDue = !hasDue
    let x = 0
    let width = openEndedWidth

    if (hasStart && hasDue) {
      const startX = scale.dateToX(row.start!)
      const dueX = scale.dateToX(row.due!)
      x = Math.min(startX, dueX)
      width = Math.max(minWidth, Math.abs(dueX - startX) + scale.unitPx)
    } else if (hasStart) {
      x = scale.dateToX(row.start!)
      width = Math.max(minWidth, openEndedWidth)
    } else {
      const dueX = scale.dateToX(row.due!)
      width = Math.max(minWidth, openEndedWidth)
      x = Math.max(0, dueX + scale.unitPx - width)
    }

    if (x + width < 0 || x > scale.totalWidth) continue

    rects.push({
      id: row.id,
      x,
      width,
      missingStart,
      missingDue,
      progress: clampProgress(row.progress),
    })
  }

  return rects
}

export function timelineBarsById(
  rects: readonly TimelineBarRect[]
): Map<string, TimelineBarRect> {
  const map = new Map<string, TimelineBarRect>()
  for (const rect of rects) map.set(rect.id, rect)
  return map
}

import type { TimelineBarRect } from "./bars"

export type TimelineDependencyEdge = {
  fromId: string
  toId: string
}

export type TimelineDependencyAnchor = {
  id: string
  x: number
  width: number
  rowIndex: number
}

export type TimelineDependencyPath = {
  fromId: string
  toId: string
  d: string
}

export type RouteDependencyPathsOptions = {
  rowHeight: number
  /** Horizontal stub before the first elbow. Defaults to 8. */
  stubPx?: number
  /** Corner radius for elbows. Defaults to 4. */
  radiusPx?: number
  /** Extra loop clearance for backward edges. Defaults to stubPx. */
  loopClearancePx?: number
}

function clampRadius(
  radius: number,
  horizontal: number,
  vertical: number
): number {
  const limit = Math.min(Math.abs(horizontal) / 2, Math.abs(vertical) / 2)
  if (!Number.isFinite(radius) || radius <= 0) return 0
  if (!Number.isFinite(limit) || limit <= 0) return 0
  return Math.min(radius, limit)
}

function rowCenterY(rowIndex: number, rowHeight: number): number {
  return rowIndex * rowHeight + rowHeight / 2
}

function forwardPath(input: {
  startX: number
  startY: number
  endX: number
  endY: number
  stub: number
  radius: number
}): string {
  const { startX, startY, endX, endY, stub, radius } = input
  if (startY === endY) {
    return `M ${startX} ${startY} H ${endX}`
  }
  const elbowX = startX + stub
  const deltaY = endY - startY
  const sign = deltaY >= 0 ? 1 : -1
  const r = clampRadius(radius, stub, deltaY)
  if (r === 0) {
    return `M ${startX} ${startY} H ${elbowX} V ${endY} H ${endX}`
  }
  return [
    `M ${startX} ${startY}`,
    `H ${elbowX - r}`,
    `Q ${elbowX} ${startY} ${elbowX} ${startY + sign * r}`,
    `V ${endY - sign * r}`,
    `Q ${elbowX} ${endY} ${elbowX + r} ${endY}`,
    `H ${endX}`,
  ].join(" ")
}

function backwardPath(input: {
  startX: number
  startY: number
  endX: number
  endY: number
  stub: number
  radius: number
  loopClearance: number
  rowHeight: number
  sameRow: boolean
}): string {
  const {
    startX,
    startY,
    endX,
    endY,
    stub,
    radius,
    loopClearance,
    rowHeight,
    sameRow,
  } = input
  const outX = startX + stub
  const loopX = Math.max(outX, endX + stub) + loopClearance
  const sign = sameRow ? 1 : endY >= startY ? 1 : -1
  const midY = sameRow ? startY + rowHeight * 0.65 * sign : endY
  const r = clampRadius(radius, loopClearance, Math.abs(midY - startY) || rowHeight)

  if (sameRow) {
    if (r === 0) {
      return [
        `M ${startX} ${startY}`,
        `H ${outX}`,
        `V ${midY}`,
        `H ${endX - stub}`,
        `V ${endY}`,
        `H ${endX}`,
      ].join(" ")
    }
    return [
      `M ${startX} ${startY}`,
      `H ${outX - r}`,
      `Q ${outX} ${startY} ${outX} ${startY + sign * r}`,
      `V ${midY - sign * r}`,
      `Q ${outX} ${midY} ${outX + r} ${midY}`,
      `H ${endX - stub - r}`,
      `Q ${endX - stub} ${midY} ${endX - stub} ${midY - sign * r}`,
      `V ${endY + sign * r}`,
      `Q ${endX - stub} ${endY} ${endX - stub + r} ${endY}`,
      `H ${endX}`,
    ].join(" ")
  }

  if (r === 0) {
    return `M ${startX} ${startY} H ${loopX} V ${endY} H ${endX}`
  }
  return [
    `M ${startX} ${startY}`,
    `H ${loopX - r}`,
    `Q ${loopX} ${startY} ${loopX} ${startY + sign * r}`,
    `V ${endY - sign * r}`,
    `Q ${loopX} ${endY} ${loopX - r} ${endY}`,
    `H ${endX}`,
  ].join(" ")
}

/**
 * Build SVG path strings for finish-to-start dependency edges.
 * Paths exit the right of the source bar and enter the left of the target bar.
 * Backward targets loop around with rounded elbows.
 */
export function routeDependencyPaths(
  edges: readonly TimelineDependencyEdge[],
  anchors: readonly TimelineDependencyAnchor[],
  options: RouteDependencyPathsOptions
): TimelineDependencyPath[] {
  const byId = new Map(anchors.map((anchor) => [anchor.id, anchor]))
  const stub = options.stubPx ?? 8
  const radius = options.radiusPx ?? 4
  const loopClearance = options.loopClearancePx ?? stub
  const rowHeight = options.rowHeight
  if (!Number.isFinite(rowHeight) || rowHeight <= 0) {
    throw new Error("rowHeight must be a positive finite number")
  }

  const paths: TimelineDependencyPath[] = []

  for (const edge of edges) {
    const from = byId.get(edge.fromId)
    const to = byId.get(edge.toId)
    if (!from || !to) continue

    const startX = from.x + from.width
    const startY = rowCenterY(from.rowIndex, rowHeight)
    const endX = to.x
    const endY = rowCenterY(to.rowIndex, rowHeight)
    const sameRow = from.rowIndex === to.rowIndex
    const forward = endX >= startX + stub

    const d = forward
      ? forwardPath({ startX, startY, endX, endY, stub, radius })
      : backwardPath({
          startX,
          startY,
          endX,
          endY,
          stub,
          radius,
          loopClearance,
          rowHeight,
          sameRow,
        })

    paths.push({ fromId: edge.fromId, toId: edge.toId, d })
  }

  return paths
}

export function anchorsFromBars(
  bars: readonly TimelineBarRect[],
  rowIndexById: ReadonlyMap<string, number>
): TimelineDependencyAnchor[] {
  const anchors: TimelineDependencyAnchor[] = []
  for (const bar of bars) {
    const rowIndex = rowIndexById.get(bar.id)
    if (rowIndex === undefined) continue
    anchors.push({
      id: bar.id,
      x: bar.x,
      width: bar.width,
      rowIndex,
    })
  }
  return anchors
}

import type { TimelineScale } from "./scale"

export type TimelineDragKind = "move" | "resize-start" | "resize-end"

export type TimelineDragOrigin = {
  start: string
  due: string
}

export type TimelineDragResult = {
  start: string
  due: string
}

export type ReduceTimelineDragInput = {
  kind: TimelineDragKind
  origin: TimelineDragOrigin
  deltaPx: number
  scale: Pick<
    TimelineScale,
    "dateToX" | "xToDate" | "snapDate" | "shiftDate" | "unitPx"
  >
}

function dayOrder(a: string, b: string): number {
  return a < b ? -1 : a > b ? 1 : 0
}

function clampDueOnOrAfterStart(start: string, due: string): TimelineDragResult {
  if (dayOrder(due, start) < 0) return { start, due: start }
  return { start, due }
}

function unitsFromDeltaPx(deltaPx: number, unitPx: number): number {
  if (!Number.isFinite(deltaPx) || !Number.isFinite(unitPx) || unitPx <= 0) {
    return 0
  }
  return Math.round(deltaPx / unitPx)
}

/**
 * Pure drag reducer for bar move and edge resize.
 * Snaps to the active zoom unit and clamps so due is never before start.
 */
export function reduceTimelineDrag(
  input: ReduceTimelineDragInput
): TimelineDragResult {
  const { kind, origin, deltaPx, scale } = input
  const units = unitsFromDeltaPx(deltaPx, scale.unitPx)
  const originStart = scale.snapDate(origin.start)
  const originDue = scale.snapDate(origin.due)

  if (kind === "move") {
    return clampDueOnOrAfterStart(
      scale.shiftDate(originStart, units),
      scale.shiftDate(originDue, units)
    )
  }

  if (kind === "resize-start") {
    const nextStart = scale.shiftDate(originStart, units)
    if (dayOrder(nextStart, originDue) > 0) {
      return { start: originDue, due: originDue }
    }
    return { start: nextStart, due: originDue }
  }

  const nextDue = scale.shiftDate(originDue, units)
  if (dayOrder(nextDue, originStart) < 0) {
    return { start: originStart, due: originStart }
  }
  return { start: originStart, due: nextDue }
}

/**
 * Keyboard nudge helper. Positive units move later in time.
 */
export function nudgeTimelineBar(input: {
  kind: TimelineDragKind
  origin: TimelineDragOrigin
  units: number
  scale: Pick<TimelineScale, "snapDate" | "shiftDate">
}): TimelineDragResult {
  const originStart = input.scale.snapDate(input.origin.start)
  const originDue = input.scale.snapDate(input.origin.due)
  const units = Number.isFinite(input.units) ? Math.trunc(input.units) : 0

  if (input.kind === "move") {
    return clampDueOnOrAfterStart(
      input.scale.shiftDate(originStart, units),
      input.scale.shiftDate(originDue, units)
    )
  }
  if (input.kind === "resize-start") {
    const nextStart = input.scale.shiftDate(originStart, units)
    if (dayOrder(nextStart, originDue) > 0) {
      return { start: originDue, due: originDue }
    }
    return { start: nextStart, due: originDue }
  }
  const nextDue = input.scale.shiftDate(originDue, units)
  if (dayOrder(nextDue, originStart) < 0) {
    return { start: originStart, due: originStart }
  }
  return { start: originStart, due: nextDue }
}

export function formatTimelineDateRange(start: string, due: string): string {
  if (start === due) return start
  return `${start} to ${due}`
}
